function latestAnswer() external view override returns (int256 answer) {
    (/* */,
        answer,/* */,/* */, /* */
    ) = _calculateBaseToQuote();
    // _checkSequencer() 미호출!
}

// 반면 latestRoundData()는:
function latestRoundData() external view override returns (...) {
    _checkSequencer();  // 시퀀서 체크 있음
