findings.vulnerable_code:
// AbstractRewardManager.sol:264-286
uint256 rewardDebt = _getAccountRewardDebtSlot()[rewardToken][account];
rewardToClaim = ((accountSharesBefore * rewardsPerVaultShare) / SHARE_PRECISION) - rewardDebt;
// rewardDebt는 transfer 전에 업데이트됨!
_getAccountRewardDebtSlot()[rewardToken][account] =
    ((accountSharesAfter * rewardsPerVaultShare) / SHARE_PRECISION);

if (0 < rewardToClaim) {
    try IEIP20NonStandard(rewardToken).transfer(account, rewardToClaim) {
        bool success = TokenUtils.checkReturnCode();
        // transfer 실패해도 rewardDebt는 이미 업데이트됨 → 리워드 영구 소실
    } catch {
        emit VaultRewardTransfer(rewardToken, account, 0);
        // catch해도 rewardDebt는 복구되지 않음
    }
}

findings.fix_suggestion:
transfer 실패 시 rewardDebt를 이전 값으로 복구하도록 수정:
uint256 prevRewardDebt = _getAccountRewardDebtSlot()[rewardToken][account];
// ... 계산 ...
try IEIP20NonStandard(rewardToken).transfer(account, rewardToClaim) {
    bool success = TokenUtils.checkReturnCode();
    if (!success) {
        // 실패 시 이전 rewardDebt로 복구
        _getAccountRewardDebtSlot()[rewardToken][account] = prevRewardDebt;
        emit VaultRewardTransfer(rewardToken, account, 0);
    }
} catch {
    _getAccountRewardDebtSlot()[rewardToken][account] = prevRewardDebt;
    emit VaultRewardTransfer(rewardToken, account, 0);
}

